    MaterialShader const* RenderSystem::FindMaterialShader( StringID const& shaderID ) const
    {
        auto const itr = VectorFind( m_materialShaders, shaderID, [] ( MaterialShader const& shader, StringID const& id )
        {
            return id == shader.m_shaderName;
        } );
        EE_ASSERT( itr != m_materialShaders.end() );
        return itr;
    }

    SurfaceShader const* RenderSystem::FindSurfaceShader( StringID const& shaderID ) const
    {
        auto const itr = VectorFind( m_surfaceShaders, shaderID, [] ( SurfaceShader const& shader, StringID const& id )
        {
            return id == shader.m_shaderName;
        } );
        EE_ASSERT( itr != m_surfaceShaders.end() );
        return itr;
    }

    ComputeShader const* RenderSystem::FindComputeShader( StringID const& shaderID ) const
    {
        auto const itr = VectorFind( m_computeShaders, shaderID, [] ( ComputeShader const& shader, StringID const& id )
        {
            return id == shader.m_shaderName;
        } );
        EE_ASSERT( itr != m_computeShaders.end() );
        return itr;
    }

    int32_t RenderSystem::FindMaterialShaderIndex( StringID const& shaderID ) const
    {
        return VectorFindIndex( m_materialShaders, shaderID, [] ( MaterialShader const& shader, StringID const& id )
        {
            return id == shader.m_shaderName;
        } );
    }

    MaterialShaderParametersInstance RenderSystem::CreateShaderParameters( size_t shaderIndex )
    {
        MaterialShader const& shaderInstance = m_materialShaders[shaderIndex];

        size_t parametersSizeInBytes = 0;
        for ( MaterialShaderParameterInfo const& parameterInfo : shaderInstance.m_parameterInfo )
        {
            parametersSizeInBytes += parameterInfo.m_parameterStrideInBytes;
        }

        EE_ASSERT( ( parametersSizeInBytes % 32 ) == 0 );

        uint32_t parametersSizeIn32ByteBlocks = uint32_t( parametersSizeInBytes / 32 );

        ShaderDataHandle handle = m_shaderDataAllocator.Allocate( parametersSizeIn32ByteBlocks );

        MaterialShaderParametersInstance parametersInstance = {};
        parametersInstance.m_handle = handle;
        parametersInstance.m_parameterInfo = TArrayView<MaterialShaderParameterInfo const>( shaderInstance.m_parameterInfo.data(), shaderInstance.m_parameterInfo.size() );
        parametersInstance.m_parametersMemory = { reinterpret_cast<uint8_t*>( handle.m_data.data() ), parametersSizeInBytes };

        parametersInstance.InitializeDefaultResourceHandles();

        return parametersInstance;
    }

    void RenderSystem::DeleteShaderParameters( MaterialShaderParametersInstance&& parameters )
    {
        EE_ASSERT( Threading::IsMainThread() );

        m_shaderDataAllocator.Deallocate( eastl::move( parameters.m_handle ) );
        parameters = {};
    }

    void RenderSystem::QueueShaderParametersUpdate( MaterialShaderParametersInstance const& parameters )
    {
        QueueShaderDataUpdate( parameters.m_handle );
    }

    // Shader data
    //-------------------------------------------------------------------------------------------------------

    ShaderDataHandle RenderSystem::CreateShaderData( uint32_t shaderDataSizeInBytes )
    {
        EE_ASSERT( Threading::IsMainThread() );

        ShaderDataHandle instanceDataHandle = m_shaderDataAllocator.Allocate( ( shaderDataSizeInBytes + 31 ) / 32 );
        return instanceDataHandle;
    }

    void RenderSystem::DeleteShaderData( ShaderDataHandle&& instanceDataHandle )
    {
        EE_ASSERT( Threading::IsMainThread() );

        m_shaderDataAllocator.Deallocate( eastl::move( instanceDataHandle ) );
        instanceDataHandle = {};
    }

    void RenderSystem::QueueShaderDataUpdate( ShaderDataHandle const& handle )
    {
        EE_ASSERT( Threading::IsMainThread() );
        EE_ASSERT( m_internalStage[m_frameIndex] == InternalStage::ResourceUpdate );

        size_t shaderDataBufferSize = m_shaderDataAllocator.GetCapacityInBytes();
        void const* pShaderDataMemory = m_shaderDataAllocator.GetData();

        if ( !m_pShaderDataBuffer || m_pShaderDataBuffer->m_size < shaderDataBufferSize )
        {
            if ( m_pShaderDataBuffer )
            {
                QueueResourceDelete( eastl::move( m_pShaderDataBuffer ) );
            }

            RHI::BufferParameters bufferParameters = {};
            bufferParameters.m_bufferSize = shaderDataBufferSize;
            bufferParameters.m_descriptorTypes.SetMultipleFlags( RHI::DescriptorTypeFlags::Buffer, RHI::DescriptorTypeFlags::Raw );
            bufferParameters.m_debugName = "System_Renderer ShaderDataBuffer";

            auto CopyBufferMemory = [pShaderDataMemory, shaderDataBufferSize] ( uint8_t* pDstMemory_WriteCombined, size_t dstSize )
            {
                EE_ASSERT( dstSize >= shaderDataBufferSize );
                Memory::CopyToWriteCombined( pDstMemory_WriteCombined, pShaderDataMemory, shaderDataBufferSize );
            };
            m_pShaderDataBuffer = QueueBufferCreate( CopyBufferMemory, bufferParameters );
        }
        else
        {
            auto CopyBufferMemory = [handle] ( uint8_t* pDstMemory_WriteCombined, size_t dstSize )
            {
                Memory::CopyToWriteCombined( pDstMemory_WriteCombined, handle.m_data.data(), handle.m_data.size_bytes() );
            };
            QueueBufferUpdate( CopyBufferMemory, m_pShaderDataBuffer, handle.m_handle.m_offset * 32, handle.m_data.size_bytes() );
        }
    }

    RHI::BufferHandle RenderSystem::GetShaderDataBufferHandle() const
    {
        return RHI::GetBufferHandle( m_pShaderDataBuffer, RHI::DescriptorTypeFlags::Buffer );
    }

