    AsyncBufferUpdate* RenderSystem::CreateBufferAsync( RHI::BufferParameters const& bufferParameters )
    {
        AsyncBufferUpdate* pBufferUpdate = EE::New<AsyncBufferUpdate>();
        pBufferUpdate->m_bufferParameters = bufferParameters;

        {
            Threading::ScopeLockWrite lock( m_asyncResourceUpdateMutex );
            m_asyncBufferUpdateQueue.push_back( pBufferUpdate );
        }

        return pBufferUpdate;
    }

